INSERT INTO FWK_TRANS_DATA_TIMES (
    TRAN_SEQ, USER_ID, TRAN_TIME, TRAN_RESULT, TRAN_REASON
) VALUES (
    #{tranSeq}, #{userId}, #{tranTime},
    #{tranResult},
    #{tranReason}
)

INSERT INTO FWK_TRANS_DATA_HIS ( TRAN_SEQ, TRAN_ID, TRAN_TYPE, TRAN_NAME, TRAN_RESULT, TRAN_TIME ) SELECT A.* FROM (
SELECT #{item.tranSeq} AS TRAN_SEQ, #{item.tranId} AS TRAN_ID, #{item.tranType} AS TRAN_TYPE, #{item.tranName} AS TRAN_NAME, #{item.tranResult} AS TRAN_RESULT, #{item.tranTime} AS TRAN_TIME FROM DUAL
) A
